func TestExtractPageItems_PrefersTagsEnvelopeKey(t *testing.T) {
	data := json.RawMessage(`{
		"tags": [{"id": "tag-1", "name": "Hot"}],
		"searchAfter": ["cursor-1"]
	}`)

	items, _, _ := extractPageItems(data, "searchAfter")
	if len(items) != 1 {
		t.Fatalf("len(items) = %d, want 1", len(items))
	}

	var item map[string]any
	if err := json.Unmarshal(items[0], &item); err != nil {
		t.Fatalf("unmarshal item: %v", err)
	}
	if got := item["id"]; got != "tag-1" {
		t.Fatalf("item id = %v, want tag-1", got)
	}
}

